BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?relType ?otherName ?direction WHERE {
  ?elem vocab:NamedElement_name ?name .
  FILTER(STR(?name) = "APS%20Black%20Box%20Specification%20TMT")
  {
    ?rel vocab:DirectedRelationship_source ?elem .
    ?rel vocab:DirectedRelationship_target ?other .
    ?rel rdf:type ?relType .
    OPTIONAL { ?other vocab:NamedElement_name ?otherName }
    BIND("outgoing" AS ?direction)
  }
  UNION
  {
    ?rel vocab:DirectedRelationship_target ?elem .
    ?rel vocab:DirectedRelationship_source ?other .
    ?rel rdf:type ?relType .
    OPTIONAL { ?other vocab:NamedElement_name ?otherName }
    BIND("incoming" AS ?direction)
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?partName ?ownerName WHERE {
  ?part rdf:type vocab:part%20property .
  ?part vocab:NamedElement_name ?partName .
  FILTER(CONTAINS(STR(?partName), "APS") || CONTAINS(STR(?partName), "aPS"))
  OPTIONAL {
    ?part vocab:Element_owner ?owner .
    ?owner vocab:NamedElement_name ?ownerName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?ownerName ?typeName ?qualName WHERE {
  ?part rdf:type vocab:part%20property .
  ?part vocab:NamedElement_name ?partName .
  FILTER(STR(?partName) = "aPS")
  ?part vocab:Element_owner ?owner .
  ?owner vocab:NamedElement_name ?ownerName .
  OPTIONAL {
    ?part vocab:TypedElement_type ?type .
    ?type vocab:NamedElement_name ?typeName .
  }
  OPTIONAL {
    ?part vocab:NamedElement_qualifiedName ?qualName .
  }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?owner ?type ?qualName WHERE {
  ?part rdf:type vocab:part%20property .
  ?part vocab:NamedElement_name ?partName .
  FILTER(STR(?partName) = "aPS")
  OPTIONAL { ?part vocab:Element_owner ?owner }
  OPTIONAL { ?part vocab:TypedElement_type ?type }
  OPTIONAL { ?part vocab:NamedElement_qualifiedName ?qualName }
}

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?portName ?portType ?ownerName WHERE {
  ?aps vocab:NamedElement_name ?apsName .
  FILTER(STR(?apsName) = "APS%20Operational%20Blackbox%20Specification%20JPL")
  ?aps vocab:EncapsulatedClassifier_ownedPort ?port .
  ?port vocab:NamedElement_name ?portName .
  OPTIONAL { ?port rdf:type ?portType }
  OPTIONAL {
    ?port vocab:Element_owner ?portOwner .
    ?portOwner vocab:NamedElement_name ?ownerName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?portName ?portType WHERE {
  <TMT/block/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Black%2520Box%2520Specification::Structure::APS%2520Operational%2520Blackbox%2520Specification%2520JPL> vocab:EncapsulatedClassifier_ownedPort ?port .
  ?port vocab:NamedElement_name ?portName .
  OPTIONAL { ?port rdf:type ?portType }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?portName ?connectedPortName ?connectedOwnerName WHERE {
  ?aps rdf:type vocab:block .
  FILTER(CONTAINS(STR(?aps), "APS%2520Operational%2520Blackbox%2520Specification%2520JPL"))
  ?aps vocab:EncapsulatedClassifier_ownedPort ?apsPort .

  ?end1 vocab:ConnectorEnd_role ?apsPort .
  ?end1 ?p1 ?connector .
  ?end2 ?p2 ?connector .
  FILTER(?end1 != ?end2)
  ?end2 vocab:ConnectorEnd_role ?otherPort .

  OPTIONAL {
    ?apsPort vocab:NamedElement_name ?portName .
  }
  OPTIONAL {
    ?otherPort vocab:NamedElement_name ?connectedPortName .
  }
  OPTIONAL {
    ?otherPort vocab:Element_owner ?connectedOwner .
    ?connectedOwner vocab:NamedElement_name ?connectedOwnerName .
  }
}
LIMIT 25
